package com.example.app.waitlist; import com.example.app.user.User; import org.springframework.security.core.annotation.AuthenticationPrincipal; import org.springframework.web.bind.annotation.*; import java.time.*; import java.util.*; @RestController @RequestMapping("/api/waitlists") public class WaitlistController { private final WaitlistService service; public WaitlistController(WaitlistService s){service=s;} @GetMapping public List<WaitlistRequest> list(@RequestParam(defaultValue="active")String view,@AuthenticationPrincipal User me){return service.list(me,view);} @GetMapping("/{id}/events") public List<WaitlistEvent> events(@PathVariable Long id,@AuthenticationPrincipal User me){return service.history(me,id);} @GetMapping("/matches") public List<WaitlistRequest> matches(@RequestParam Long serviceId,@RequestParam LocalDateTime start,@AuthenticationPrincipal User me){return service.matches(me,serviceId,start);} public record OfferBody(LocalDateTime slotStart,LocalDateTime slotEnd,Long employeeId,Integer validityMinutes){} @PostMapping("/{id}/offer") public WaitlistOffer offer(@PathVariable Long id,@RequestBody OfferBody b,@AuthenticationPrincipal User me){return service.offer(me,id,b.slotStart(),b.slotEnd(),b.employeeId(),b.validityMinutes());} @PostMapping("/{id}/convert-to-booking") public WaitlistRequest convert(@PathVariable Long id,@RequestParam Long bookingId,@AuthenticationPrincipal User me){return service.convert(me,id,bookingId);} @DeleteMapping("/{id}") public WaitlistRequest remove(@PathVariable Long id,@AuthenticationPrincipal User me){return service.remove(me,id);} }